static time_t tm_to_time_t(const struct atm *tm)
{
	static const int mdays[] = {
	    0, 31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334
	};
	int year = tm->tm_year - 70;
	int month = tm->tm_mon;
	int day = tm->tm_mday;
	if (year < 0 || year > 129) 
		return -1;
	if (month < 0 || month > 11) 
		return -1;
