	if (num >= 100000000 && nodate((struct tm*)tm)) {
		time_t time = num;
		if (gmtime_r(&time, (struct tm*)tm)) {
			*tm_gmt = 1;
			return end - date;
		}
	}

	switch (*end) {
	case ':':
	case '.':
	case '/':
	case '-':
		if (isdigit(end[1])) {
			int match = match_multi_number(num, *end, date, end, tm, 0);
			if (match)
				return match;
		}
	}

	n = 0;
	do {
		n++;
	} while (isdigit(date[n]));

	if (n == 4) {
		if (num <= 1400 && *offset == -1) {
			unsigned int minutes = num % 100;
			unsigned int hours = num / 100;
			*offset = hours*60 + minutes;
		} else if (num > 1900 && num < 2100)
			tm->tm_year = num - 1900;
		return n;
	}

	if (n > 2)
		return n;

	if (num > 0 && num < 32 && tm->tm_mday < 0) {
		tm->tm_mday = num;
		return n;
	}

	if (n == 2 && tm->tm_year < 0) {
		if (num < 10 && tm->tm_mday >= 0) {
			tm->tm_year = num + 100;
			return n;
		}
		if (num >= 70) {
			tm->tm_year = num;
			return n;
		}
	}
	if (num > 0 && num < 13 && tm->tm_mon < 0)
		tm->tm_mon = num-1;
	return n;
}
static int match_tz(const char *date, int *offp)
{
	char *end;
	int hour = strtoul(date + 1, &end, 10);
	int n = end - (date + 1);
	int min = 0;
	if (n == 4) {

		min = hour % 100;
		hour = hour / 100;
	} else if (n != 2) {
		min = 99; 
	} else if (*end == ':') {

		min = strtoul(end + 1, &end, 10);
		if (end - (date + 1) != 5)
			min = 99; 
	} 

	if (min < 60 && hour < 24) {
		int offset = hour * 60 + min;
		if (*date == '-')
			offset = -offset;
		*offp = offset;
	}
	return end - date;
}
static int match_object_header_date(const char *date, struct timeval *tv, int *offset)
{
	char *end;
	unsigned long stamp;
	int ofs;
	if (*date < '0' || '9' < *date)
		return -1;
	stamp = strtoul(date, &end, 10);
	if (*end != ' ' || stamp == ULONG_MAX || (end[1] != '+' && end[1] != '-'))
		return -1;
	date = end + 2;
	ofs = strtol(date, &end, 10);
	if ((*end != '\0' && (*end != '\n')) || end != date + 4)
		return -1;
	ofs = (ofs / 100) * 60 + (ofs % 100);
	if (date[-1] == '-')
		ofs = -ofs;
	tv->tv_sec = stamp;
	*offset = ofs;
	return 0;
}
int parse_date_basic(const char *date, struct timeval *tv, int *offset)
{
	struct atm tm;
	int tm_gmt;
	int dummy_offset;
	if (!offset)
		offset = &dummy_offset;
	memset(&tm, 0, sizeof(tm));
	tm.tm_year = -1;
	tm.tm_mon = -1;
	tm.tm_mday = -1;
	tm.tm_isdst = -1;
	tm.tm_hour = -1;
	tm.tm_min = -1;
	tm.tm_sec = -1;
	tm.tm_usec = 0;
	*offset = -1;
	tm_gmt = 0;
	if (*date == '@' &&
	    !match_object_header_date(date + 1, tv, offset))
		return 0; 
	for (;;) {
		int match = 0;
		unsigned char c = *date;

		if (!c || c == '\n')
			break;
		if (isalpha(c))
			match = match_alpha(date, &tm, offset);
		else if (isdigit(c))
			match = match_digit(date, &tm, offset, &tm_gmt);
		else if ((c == '-' || c == '+') && isdigit(date[1]))
			match = match_tz(date, offset);
		if (!match) {

			match = 1;
		}
		date += match;
	}
	tv->tv_usec = tm.tm_usec;

	tv->tv_sec = tm_to_time_t(&tm);
	if (*offset == -1) {
		time_t temp_time = mktime((struct tm*)&tm);
		if (tv->tv_sec > temp_time) {
			*offset = (tv->tv_sec - temp_time) / 60;
		} else {
			*offset = -(int)((temp_time - tv->tv_sec) / 60);
		}
	}
	if (*offset == -1)
		*offset = (((time_t)tv->tv_sec) - mktime((struct tm*)&tm)) / 60;
	if (tv->tv_sec == -1)
		return -1;
	if (!tm_gmt)
		tv->tv_sec -= *offset * 60;
	return 0; 
